function importJSON(e) {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
        try {
            const loadedState = JSON.parse(event.target.result);
            Object.assign(state, loadedState);
            
            saveConfig().then(() => {
                alert('');
                location.reload();
            });
        } catch (err) {
            alert('');
            console.error(err);
        }
    };
    reader.readAsText(file);
}

